    27	inline cxx20::expected<ResultT, Error>
    28	stringToInteger(ConvResultT (&Conv)(const char *, char **, int),
    29	                std::string Value) noexcept {
    30	  using namespace std::literals;
    31	  char *EndPtr;
    32	  const char *CStr = Value.c_str();
    33	  auto SavedErrNo = std::exchange(errno, 0);
    34	  const auto Result = Conv(CStr, &EndPtr, 10);
    35	  std::swap(SavedErrNo, errno);
    36	  if (EndPtr == CStr) {
    37	    return cxx20::unexpected<Error>(std::in_place, ErrCode::InvalidArgument,
    38	                                    ""s);
    39	  }
    40	  auto InsideRange = [](auto WiderResult) constexpr noexcept {
    41	    using WiderResultT = decltype(WiderResult);
    42	    if constexpr (std::is_same_v<ResultT, WiderResultT>) {
    43	      return true;
    44	    } else {
    45	      return static_cast<WiderResultT>(std::numeric_limits<ResultT>::min()) <=
    46	                 WiderResult &&
    47	             WiderResult <=
    48	                 static_cast<WiderResultT>(std::numeric_limits<ResultT>::max());
    49	    }
    50	  };
    51	  if (SavedErrNo == ERANGE || !InsideRange(Result)) {
    52	    return cxx20::unexpected<Error>(std::in_place, ErrCode::OutOfRange, ""s);
    53	  }
