#include "po/argument_parser.h"
#include "po/list.h"
#include "po/option.h"

#include <cstdio>
#include <cstdlib>
#include <iostream>
#include <string>
#include <string_view>
#include <vector>

using namespace WasmEdge::PO;

struct Result {
  bool Ok;
  std::string Output;
  int Value;
};

Result run_int(std::vector<const char *> Args) {
  Option<int> Num(Description("number"), DefaultValue<int>(-1));
  ArgumentParser Parser;
  Parser.add_option("num", Num);

  FILE *Out = std::tmpfile();
  if (!Out) {
    std::perror("tmpfile");
    std::exit(2);
  }
  const bool Ok = Parser.parse(Out, static_cast<int>(Args.size()), Args.data());
  std::fflush(Out);
  std::fseek(Out, 0, SEEK_END);
  const long Size = std::ftell(Out);
  std::string Output(Size > 0 ? static_cast<std::size_t>(Size) : 0, '\0');
  std::rewind(Out);
  if (!Output.empty()) {
    std::fread(Output.data(), 1, Output.size(), Out);
  }
  std::fclose(Out);
  return {Ok, Output, Num.value()};
}

bool expect_failure(std::string_view Name, std::vector<const char *> Args,
                    std::string_view ExpectedMessage) {
  const Result R = run_int(std::move(Args));
  const bool Passed = !R.Ok && R.Output.find(ExpectedMessage) != std::string::npos;
  std::cout << Name << ": ok=" << R.Ok << " value=" << R.Value
            << " output='" << R.Output << "' => "
            << (Passed ? "PASS" : "FAIL") << '\n';
  return Passed;
}

bool expect_success(std::string_view Name, std::vector<const char *> Args,
                    int ExpectedValue) {
  const Result R = run_int(std::move(Args));
  const bool Passed = R.Ok && R.Value == ExpectedValue;
  std::cout << Name << ": ok=" << R.Ok << " value=" << R.Value
            << " output='" << R.Output << "' => "
            << (Passed ? "PASS" : "FAIL") << '\n';
  return Passed;
}

int main() {
  bool Passed = true;
  Passed &= expect_failure("equals trailing", {"test", "--num=100abc"},
                           "invalid integer value: 100abc");
  Passed &= expect_failure("space trailing", {"test", "--num", "100abc"},
                           "invalid integer value: 100abc");
  Passed &= expect_failure("equals no digits", {"test", "--num=abc"},
                           "invalid integer value: abc");
  Passed &= expect_failure("space no digits", {"test", "--num", "abc"},
                           "invalid integer value: abc");
  Passed &= expect_success("valid", {"test", "--num=100"}, 100);
  return Passed ? 0 : 1;
}
