#include "po/argument_parser.h"
#include "po/option.h"

#include <cstdio>
#include <cstdlib>
#include <iostream>
#include <string>
#include <string_view>
#include <vector>

using namespace WasmEdge::PO;

struct Result {
  bool Ok;
  std::string Output;
  std::string Value;
};

std::string read_output(FILE *Out) {
  std::fflush(Out);
  std::fseek(Out, 0, SEEK_END);
  const long Size = std::ftell(Out);
  std::string Output(Size > 0 ? static_cast<std::size_t>(Size) : 0, '\0');
  std::rewind(Out);
  if (!Output.empty()) {
    std::fread(Output.data(), 1, Output.size(), Out);
  }
  return Output;
}

FILE *make_output() {
  FILE *Out = std::tmpfile();
  if (!Out) {
    std::perror("tmpfile");
    std::exit(2);
  }
  return Out;
}

Result run_int(std::vector<const char *> Args) {
  Option<int> Num(Description("number"), DefaultValue<int>(-1));
  ArgumentParser Parser;
  Parser.add_option("num", Num);
  FILE *Out = make_output();
  const bool Ok = Parser.parse(Out, static_cast<int>(Args.size()), Args.data());
  std::string Output = read_output(Out);
  std::fclose(Out);
  return {Ok, Output, std::to_string(Num.value())};
}

Result run_float(std::vector<const char *> Args) {
  Option<float> Num(Description("number"), DefaultValue<float>(-1.0F));
  ArgumentParser Parser;
  Parser.add_option("float", Num);
  FILE *Out = make_output();
  const bool Ok = Parser.parse(Out, static_cast<int>(Args.size()), Args.data());
  std::string Output = read_output(Out);
  std::fclose(Out);
  return {Ok, Output, std::to_string(Num.value())};
}

Result run_toggle(std::vector<const char *> Args) {
  Option<Toggle> Flag(Description("flag"));
  ArgumentParser Parser;
  Parser.add_option("flag", Flag);
  FILE *Out = make_output();
  const bool Ok = Parser.parse(Out, static_cast<int>(Args.size()), Args.data());
  std::string Output = read_output(Out);
  std::fclose(Out);
  return {Ok, Output, Flag.value() ? "true" : "false"};
}

bool expect_failure(std::string_view Name, Result R,
                    std::string_view ExpectedMessage) {
  const bool Passed = !R.Ok && R.Output.find(ExpectedMessage) != std::string::npos;
  std::cout << Name << ": ok=" << R.Ok << " value=" << R.Value
            << " output='" << R.Output << "' => "
            << (Passed ? "PASS" : "FAIL") << '\n';
  return Passed;
}

bool expect_success(std::string_view Name, Result R, std::string_view Value) {
  const bool Passed = R.Ok && R.Value.find(Value) == 0 && R.Output.empty();
  std::cout << Name << ": ok=" << R.Ok << " value=" << R.Value
            << " output='" << R.Output << "' => "
            << (Passed ? "PASS" : "FAIL") << '\n';
  return Passed;
}

int main() {
  bool Passed = true;
  Passed &= expect_failure("equals trailing", run_int({"test", "--num=100abc"}),
                           "invalid integer value: 100abc");
  Passed &= expect_failure("space trailing", run_int({"test", "--num", "100abc"}),
                           "invalid integer value: 100abc");
  Passed &= expect_failure("equals no digits", run_int({"test", "--num=abc"}),
                           "invalid integer value: abc");
  Passed &= expect_failure("space no digits", run_int({"test", "--num", "abc"}),
                           "invalid integer value: abc");
  Passed &= expect_failure("integer range", run_int({"test", "--num=999999999999999999999999"}),
                           "integer value out of range: 999999999999999999999999");
  Passed &= expect_failure("float trailing", run_float({"test", "--float=1.5abc"}),
                           "invalid floating value: 1.5abc");
  Passed &= expect_failure("toggle argument spacing", run_toggle({"test", "--flag=1"}),
                           "option flag doesn't need arguments.");
  Passed &= expect_success("valid int", run_int({"test", "--num=100"}), "100");
  Passed &= expect_success("valid space int", run_int({"test", "--num", "42"}), "42");
  Passed &= expect_success("valid float", run_float({"test", "--float=1.5"}), "1.500000");
  return Passed ? 0 : 1;
}
